const keys = {

  // ── University Mathematics f5-f7 ─────────────────────────────────────

  "learnUni_mathematics_f5_name": "Real Analysis",
  "learnUni_mathematics_f5_desc": "Real analysis is the rigorous foundation of calculus, proving results about limits, continuity, differentiation, and integration using precise ε-δ definitions. It replaces intuitive reasoning with watertight logical arguments — a fundamental shift in mathematical maturity required at university level.",
  "learnUni_mathematics_f5_kp0": "ε-δ limit: lim_{x→a} f(x) = L means for every ε>0 there exists δ>0 such that 0<|x−a|<δ implies |f(x)−L|<ε. This eliminates ambiguity from the concept of 'approaching'.",
  "learnUni_mathematics_f5_kp1": "Bolzano-Weierstrass theorem: every bounded sequence in ℝⁿ has a convergent subsequence. Heine-Borel: a subset of ℝⁿ is compact iff it is closed and bounded.",
  "learnUni_mathematics_f5_kp2": "Intermediate Value Theorem: if f is continuous on [a,b] and f(a) and f(b) have opposite signs, there exists c ∈ (a,b) with f(c) = 0. Proved rigorously from completeness of ℝ.",
  "learnUni_mathematics_f5_kp3": "Uniform continuity: a single δ works for all x simultaneously — stronger than pointwise continuity. Every continuous function on a compact set is uniformly continuous.",
  "learnUni_mathematics_f5_kp4": "Riemann vs. Lebesgue integral: the Lebesgue integral extends Riemann's by measuring sets (measure theory) and handles far more functions, including limits of sequences.",
  "learnUni_mathematics_f5_task": "Using the ε-δ definition, prove that lim_{x→3} (2x−1) = 5. Then use the IVT to show that x⁵ − x − 1 = 0 has at least one real solution. Prove that f(x) = 1/x is not uniformly continuous on (0,1) but is on [0.5, 2].",
  "learnUni_mathematics_f5_tp0": "ε-δ limits and continuity",
  "learnUni_mathematics_f5_tp1": "Compactness and IVT",
  "learnUni_mathematics_f5_tp2": "Uniform continuity and integration",

  "learnUni_mathematics_f6_name": "Abstract Algebra",
  "learnUni_mathematics_f6_desc": "Abstract algebra generalises arithmetic operations to abstract structures: groups (one operation), rings (two operations), and fields (two operations with inverses). This unifies disparate mathematics and underpins modern cryptography (elliptic curves over finite fields) and physics (symmetry groups in particle physics).",
  "learnUni_mathematics_f6_kp0": "Group axioms: closure (a★b ∈ G), associativity ((a★b)★c = a★(b★c)), identity (e★a = a), inverse (a★a⁻¹ = e). Examples: (ℤ,+), (ℚ\\{0},×), dihedral group Dₙ (symmetries of n-gon).",
  "learnUni_mathematics_f6_kp1": "Lagrange's theorem: if H is a subgroup of finite group G, then |H| divides |G|. Corollary: order of any element divides |G|. Normal subgroups allow quotient group construction G/N.",
  "learnUni_mathematics_f6_kp2": "Ring theory: (R,+,×) where (R,+) is abelian group, × is associative and distributive. Integral domains (no zero divisors). Ideals generalise subgroups for rings. Principal ideal domains (PIDs): every ideal generated by one element.",
  "learnUni_mathematics_f6_kp3": "Fields: every nonzero element has a multiplicative inverse. Examples: ℚ, ℝ, ℂ, and finite fields 𝔽_p = ℤ/pℤ (p prime). Finite fields underpin AES encryption and error-correcting codes.",
  "learnUni_mathematics_f6_kp4": "Galois theory: connects roots of polynomials to group theory. Galois group of a polynomial captures the symmetries of its roots. A polynomial is solvable by radicals iff its Galois group is a solvable group — explains the insolvability of degree≥5 general equations.",
  "learnUni_mathematics_f6_task": "Prove that ℤ₆ under addition is a group. Find all subgroups and verify Lagrange's theorem. Prove ℤ₂×ℤ₃ ≅ ℤ₆ by exhibiting an explicit isomorphism. Then show ℤ₂×ℤ₂ ≇ ℤ₄ by finding a property that distinguishes them.",
  "learnUni_mathematics_f6_tp0": "Groups, subgroups, and Lagrange",
  "learnUni_mathematics_f6_tp1": "Rings and fields",
  "learnUni_mathematics_f6_tp2": "Galois theory",

  "learnUni_mathematics_f7_name": "Complex Analysis",
  "learnUni_mathematics_f7_desc": "Complex analysis extends calculus to functions of a complex variable. Holomorphic (complex-differentiable) functions are infinitely differentiable and encode global information in local data. Cauchy's integral theorem, residue calculus, and conformal mappings make it powerful across physics, engineering, and number theory.",
  "learnUni_mathematics_f7_kp0": "Complex differentiation: f'(z) = lim_{h→0} [f(z+h)−f(z)]/h (h ∈ ℂ). Cauchy-Riemann equations: if f = u+iv is holomorphic then ∂u/∂x = ∂v/∂y and ∂u/∂y = −∂v/∂x.",
  "learnUni_mathematics_f7_kp1": "Cauchy's integral theorem: for holomorphic f inside and on simple closed contour C, ∮_C f(z) dz = 0. Cauchy's formula: f(z₀) = (1/2πi) ∮_C f(z)/(z−z₀) dz.",
  "learnUni_mathematics_f7_kp2": "Taylor and Laurent series: holomorphic functions expand as power series. Laurent series allows negative powers — essential near isolated singularities (poles, essential singularities).",
  "learnUni_mathematics_f7_kp3": "Residue theorem: ∮_C f(z) dz = 2πi × Σ Res(f, zₖ) for all poles zₖ inside C. Residue at simple pole z₀: Res = lim_{z→z₀} (z−z₀)f(z). Used to evaluate real integrals by clever contour choice.",
  "learnUni_mathematics_f7_kp4": "Conformal mappings: holomorphic functions with non-zero derivative preserve angles locally. Möbius transformations map circles/lines to circles/lines. Used in fluid dynamics, electrostatics, and cartography.",
  "learnUni_mathematics_f7_task": "Verify f(z)=z² is holomorphic via Cauchy-Riemann equations. Compute ∮_{|z|=2} dz/(z²−1) using the residue theorem: find poles, check which lie inside |z|=2, compute residues, and apply the theorem. Verify by partial fractions.",
  "learnUni_mathematics_f7_tp0": "Holomorphic functions and C-R equations",
  "learnUni_mathematics_f7_tp1": "Cauchy's theorem and formula",
  "learnUni_mathematics_f7_tp2": "Residue theorem and applications",

  // ── University Physics f2-f5 ─────────────────────────────────────────

  "learnUni_physics_f2_name": "Classical Electrodynamics",
  "learnUni_physics_f2_desc": "Maxwell's equations unify electricity, magnetism, and optics into one elegant framework. They predict electromagnetic waves travelling at c, explain radiation, and form the basis of all electrical engineering. Understanding them at the vector calculus level is a hallmark of a physics education.",
  "learnUni_physics_f2_kp0": "Maxwell's equations: ∇·E = ρ/ε₀, ∇·B = 0, ∇×E = −∂B/∂t, ∇×B = μ₀(J + ε₀∂E/∂t). Together they unify all classical electromagnetic phenomena.",
  "learnUni_physics_f2_kp1": "Electromagnetic waves: in free space, E and B satisfy ∇²E = μ₀ε₀∂²E/∂t², giving wave speed c = 1/√(μ₀ε₀) ≈ 3×10⁸ m/s. Light is an electromagnetic wave.",
  "learnUni_physics_f2_kp2": "Poynting vector S = (1/μ₀) E×B: direction and rate of electromagnetic energy flow. Radiation pressure: EM waves carry momentum p = U/c.",
  "learnUni_physics_f2_kp3": "Boundary conditions at material interfaces: tangential E and normal B are continuous. Determines reflection and refraction (Fresnel equations give amplitudes; Snell's law gives angles).",
  "learnUni_physics_f2_kp4": "Multipole expansion: far from a charge distribution, fields are dominated by leading terms — monopole (1/r²), dipole (1/r³), quadrupole (1/r⁴). Oscillating dipoles radiate EM waves — basis of antennas.",
  "learnUni_physics_f2_task": "Starting from Maxwell's equations in vacuum (ρ=0, J=0), derive the electromagnetic wave equation for E. Show c = 1/√(μ₀ε₀). Then write the fields for a plane wave propagating in the z-direction and show that E, B, and k are mutually perpendicular and that |E|/|B| = c.",
  "learnUni_physics_f2_tp0": "Maxwell's equations",
  "learnUni_physics_f2_tp1": "EM waves and Poynting vector",
  "learnUni_physics_f2_tp2": "Radiation and multipoles",

  "learnUni_physics_f3_name": "Thermodynamics & Statistical Mechanics",
  "learnUni_physics_f3_desc": "Statistical mechanics derives macroscopic thermodynamics from the statistical behaviour of microscopic constituents. The Boltzmann distribution, partition function, and entropy as log of microstates connect atomic physics to everyday thermal phenomena — from black-body radiation to phase transitions.",
  "learnUni_physics_f3_kp0": "Boltzmann distribution: probability of microstate with energy E is P ∝ e^{−E/k_BT}. Higher temperature allows occupation of higher energy states. This single equation underlies chemistry, astrophysics, and biology.",
  "learnUni_physics_f3_kp1": "Partition function Z = Σᵢ e^{−βEᵢ} (β=1/k_BT). Free energy F = −k_BT ln Z. All thermodynamic quantities follow: ⟨E⟩ = −∂ln Z/∂β, entropy S = −∂F/∂T, pressure P = −∂F/∂V.",
  "learnUni_physics_f3_kp2": "Boltzmann entropy: S = k_B ln Ω (Ω = number of microstates). Second law: Ω increases spontaneously → S always increases in isolated systems. Arrow of time emerges from statistics.",
  "learnUni_physics_f3_kp3": "Quantum statistics: bosons obey Bose-Einstein distribution (multiple particles per state → superfluidity, lasers, Bose-Einstein condensate). Fermions obey Fermi-Dirac (one per state → electron structure of metals, white dwarfs, neutron stars).",
  "learnUni_physics_f3_kp4": "Phase transitions: at critical temperature Tc, order parameter jumps (1st order) or rises continuously (2nd order). Ising model captures ferromagnetism. Near critical point: universal scaling laws, divergent correlation length, universality classes.",
  "learnUni_physics_f3_task": "Derive the partition function for a two-level system (energies 0 and ε). Find ⟨E⟩, C_V = ∂⟨E⟩/∂T, and entropy S. Sketch C_V vs. T (Schottky peak). Interpret the peak physically. Apply the Boltzmann factor to estimate the fraction of molecules in an excited state at T = 300 K if ε = 0.025 eV.",
  "learnUni_physics_f3_tp0": "Boltzmann distribution and partition function",
  "learnUni_physics_f3_tp1": "Entropy and the second law",
  "learnUni_physics_f3_tp2": "Quantum statistics and phase transitions",

  "learnUni_physics_f4_name": "Quantum Mechanics",
  "learnUni_physics_f4_desc": "Quantum mechanics is the most accurately tested physical theory, correct to 12 decimal places in QED predictions. It replaces classical trajectories with wavefunctions evolving under the Schrödinger equation and explains atoms, molecules, lasers, semiconductors, and MRI scanners. It is also deeply philosophically puzzling.",
  "learnUni_physics_f4_kp0": "Wavefunction ψ(x,t): |ψ|² is probability density. Normalisation: ∫|ψ|² dx = 1. Time evolution: iℏ ∂ψ/∂t = Ĥψ. Stationary states: Ĥψ_n = E_n ψ_n — energy eigenstates.",
  "learnUni_physics_f4_kp1": "Infinite square well: ψ_n = √(2/L) sin(nπx/L), E_n = n²π²ℏ²/(2mL²). Quantised energy levels — explains atomic spectra. Zero-point energy E₁ > 0 even at T=0.",
  "learnUni_physics_f4_kp2": "Quantum harmonic oscillator: E_n = (n+½)ℏω, n=0,1,2,... Raising/lowering operators â±. Ground state has Gaussian wavefunction. Models molecular vibrations and field quanta.",
  "learnUni_physics_f4_kp3": "Hydrogen atom: spherically symmetric Coulomb potential. Solutions labelled by quantum numbers n (energy), l (angular momentum), m (magnetic). Orbital shapes (s, p, d, f) determine chemical bonding.",
  "learnUni_physics_f4_kp4": "Entanglement and Bell's theorem: two particles can be correlated in ways that cannot be explained by local hidden variables. Bell inequalities violated experimentally — proves non-locality of quantum mechanics. Basis for quantum cryptography.",
  "learnUni_physics_f4_task": "Solve the 1D infinite square well: write ψ_n and E_n. Calculate E₁ for an electron in L = 1 nm well. A particle is prepared in ψ = (1/√2)(ψ₁ + ψ₂). (a) Is this an energy eigenstate? (b) Calculate ⟨E⟩. (c) Describe how ⟨x⟩ evolves in time. (d) Explain what happens when you measure the energy.",
  "learnUni_physics_f4_tp0": "Wavefunction and Schrödinger equation",
  "learnUni_physics_f4_tp1": "Harmonic oscillator and hydrogen atom",
  "learnUni_physics_f4_tp2": "Entanglement and quantum information",

  "learnUni_physics_f5_name": "Optics & Photonics",
  "learnUni_physics_f5_desc": "Modern optics treats light both as an electromagnetic wave (wave optics) and as photons (quantum optics). Wave optics explains interference, diffraction, and polarisation precisely. Photonics — the science and technology of photon generation and control — underpins lasers, optical fibres, solar cells, and emerging quantum technologies.",
  "learnUni_physics_f5_kp0": "Wave optics: interference and diffraction arise from Huygens-Fresnel principle (each wavefront point is a secondary source). Young's double slit gives fringe spacing Δy = λL/d.",
  "learnUni_physics_f5_kp1": "Fourier optics: a lens performs a Fourier transform in the focal plane. Spatial filtering — blocking certain spatial frequencies — is the basis of image processing and microscopy.",
  "learnUni_physics_f5_kp2": "Laser physics: population inversion achieved by optical or electrical pumping. Stimulated emission produces coherent, monochromatic, directional light. Laser cavities select modes. Applications: surgery, lidar, optical tweezers, barcode scanning.",
  "learnUni_physics_f5_kp3": "Optical fibres: total internal reflection (angle > critical angle θ_c = arcsin(n₂/n₁)) traps light in core. Single-mode fibres for long-haul communications; multi-mode for short distances. Attenuation ~0.2 dB/km at 1550 nm.",
  "learnUni_physics_f5_kp4": "Quantum optics: photon statistics (coherent vs. thermal vs. squeezed light), single-photon sources, entangled photon pairs (via spontaneous parametric down-conversion). Applications: quantum key distribution (BB84 protocol), quantum teleportation.",
  "learnUni_physics_f5_task": "A diffraction grating with 500 lines/mm is illuminated by light of λ=600 nm. Find the angles for m=1 and m=2 diffraction orders. Calculate the resolving power R = mN for N = 1000 lines. Then design an optical fibre with core n₁=1.50 and cladding n₂=1.45: find the critical angle and the numerical aperture NA = √(n₁²−n₂²).",
  "learnUni_physics_f5_tp0": "Wave optics and interference",
  "learnUni_physics_f5_tp1": "Laser physics",
  "learnUni_physics_f5_tp2": "Optical fibres and quantum optics",

  // ── University Chemistry f0-f4 ───────────────────────────────────────

  "learnUni_chemistry_f0_name": "Physical Chemistry",
  "learnUni_chemistry_f0_desc": "Physical chemistry applies physics — thermodynamics, kinetics, quantum mechanics — to chemical systems. It explains why reactions occur (thermodynamics), how fast they proceed (kinetics), and what determines molecular structure (quantum chemistry). It is the theoretical backbone of all chemistry.",
  "learnUni_chemistry_f0_kp0": "Gibbs free energy: ΔG = ΔH − TΔS. ΔG < 0: spontaneous; ΔG > 0: non-spontaneous; ΔG = 0: equilibrium. At equilibrium: ΔG° = −RT ln K.",
  "learnUni_chemistry_f0_kp1": "Chemical kinetics: rate = k[A]ᵐ[B]ⁿ. First-order: t₁/₂ = ln2/k. Arrhenius equation: k = Ae^{−Ea/RT}. Transition state theory: rate determined by ΔG‡ (Gibbs energy of transition state).",
  "learnUni_chemistry_f0_kp2": "Molecular orbital theory: atomic orbitals combine (LCAO) to form bonding (lower energy) and antibonding (higher energy) MOs. Bond order = ½(bonding − antibonding electrons).",
  "learnUni_chemistry_f0_kp3": "Spectroscopy: UV-Vis (Beer-Lambert: A=εcl, electronic transitions), IR (molecular vibrations — functional group fingerprints), NMR (nuclear spin environments give connectivity and stereochemistry), mass spec (molecular mass and fragmentation).",
  "learnUni_chemistry_f0_kp4": "Colligative properties (depend on number of solute particles, not identity): boiling point elevation (ΔT_b = K_b m), freezing point depression (ΔT_f = K_f m), osmotic pressure (Π = MRT). Used in cryoscopy and osmometry.",
  "learnUni_chemistry_f0_task": "For the reaction N₂ + 3H₂ → 2NH₃ at 298 K, ΔH° = −92 kJ/mol and ΔS° = −198 J/mol·K. (a) Calculate ΔG° and K. (b) Is the reaction spontaneous at 298 K? At 600 K? (c) Interpret how temperature and pressure affect yield in the Haber process. Relate to Le Chatelier's principle.",
  "learnUni_chemistry_f0_tp0": "Gibbs free energy and equilibrium",
  "learnUni_chemistry_f0_tp1": "Kinetics and Arrhenius equation",
  "learnUni_chemistry_f0_tp2": "Spectroscopy and molecular orbital theory",

  "learnUni_chemistry_f1_name": "Organic Chemistry (University)",
  "learnUni_chemistry_f1_desc": "University organic chemistry studies reaction mechanisms at the electron level, stereochemistry, synthesis planning, and functional group transformations. Mastery is essential for pharmacology, materials science, biochemistry, and chemical biology.",
  "learnUni_chemistry_f1_kp0": "Curly arrow formalism: full-headed arrows show electron pair movement (nucleophile to electrophile). Half-headed arrows show radical mechanisms. Every arrow must start from an electron source (lone pair or bond).",
  "learnUni_chemistry_f1_kp1": "SN2 mechanism: concerted one-step backside attack → inversion of configuration (Walden inversion). Favoured: strong nucleophile, primary substrate, polar aprotic solvent (DMF, DMSO, acetone).",
  "learnUni_chemistry_f1_kp2": "SN1 mechanism: two steps via carbocation intermediate. Favoured: tertiary substrate, polar protic solvent (water, ethanol). Rate = k[substrate] only. Gives racemisation.",
  "learnUni_chemistry_f1_kp3": "Stereochemistry: chiral centres, enantiomers, diastereomers. Cahn-Ingold-Prelog (CIP) rules assign R/S configuration. Optical activity measured by polarimetry. Thalidomide: R-enantiomer therapeutic, S-enantiomer teratogenic — the importance of stereochemical purity.",
  "learnUni_chemistry_f1_kp4": "Retrosynthetic analysis (Corey): plan synthesis backwards — identify disconnections (breaking key bonds) to expose readily available starting materials. Protecting group strategy, functional group interconversions, and oxidation state tracking are key skills.",
  "learnUni_chemistry_f1_task": "Propose a complete mechanism with curly arrows for: (a) SN2 reaction of (R)-2-bromobutane with NaOH — show the product configuration, (b) SN1 reaction of (CH₃)₃CBr with water — show the carbocation, racemisation, and both stereoisomers of the product. Explain why the same substrate cannot undergo both mechanisms simultaneously.",
  "learnUni_chemistry_f1_tp0": "Reaction mechanisms and curly arrows",
  "learnUni_chemistry_f1_tp1": "SN1 vs. SN2 and stereochemistry",
  "learnUni_chemistry_f1_tp2": "Retrosynthetic analysis",

  "learnUni_chemistry_f2_name": "Inorganic Chemistry",
  "learnUni_chemistry_f2_desc": "Inorganic chemistry encompasses coordination chemistry, organometallics, solid-state materials, and bioinorganic chemistry. Transition metals with their rich d-orbital chemistry underlie industrial catalysis, functional materials, and essential biological processes.",
  "learnUni_chemistry_f2_kp0": "Coordination complexes: central metal ion + ligands (Lewis bases donating electron pairs). Chelate effect: polydentate ligands (EDTA) form more stable complexes than monodentate ones — thermodynamic advantage from entropy.",
  "learnUni_chemistry_f2_kp1": "Crystal field theory (CFT): d-orbitals split in a ligand field. Octahedral splitting Δ_o separates t₂g (lower) and e_g (higher) sets. Strong field ligands (CN⁻, CO) → large Δ_o → low spin. Weak field (F⁻, H₂O) → small Δ_o → high spin.",
  "learnUni_chemistry_f2_kp2": "Colour and magnetism from CFT: d-d transitions absorb visible light → complementary colour observed. High-spin complexes are paramagnetic (unpaired electrons); low-spin are diamagnetic.",
  "learnUni_chemistry_f2_kp3": "Organometallic chemistry: metal-carbon bonds (metal carbonyls M(CO)ₙ, metallocenes, Wilkinson's catalyst [RhCl(PPh₃)₃] for hydrogenation). 18-electron rule predicts stability of organometallic complexes.",
  "learnUni_chemistry_f2_kp4": "Bioinorganic chemistry: Fe in haemoglobin (reversible O₂ binding), Fe-S clusters (electron transfer), Zn in carbonic anhydrase, Mg in chlorophyll (photosynthesis), Cu in cytochrome c oxidase (respiration), Co in Vitamin B₁₂.",
  "learnUni_chemistry_f2_task": "Draw the octahedral splitting diagram for [Fe(CN)₆]³⁻ and [Fe(H₂O)₆]³⁺. Assign electrons using CFT, determine spin state and number of unpaired electrons for each. Predict which absorbs higher-energy light and why. Calculate the oxidation state of Fe in each complex and identify the ligands as strong or weak field using the spectrochemical series.",
  "learnUni_chemistry_f2_tp0": "Coordination chemistry and CFT",
  "learnUni_chemistry_f2_tp1": "Colour, magnetism, and organometallics",
  "learnUni_chemistry_f2_tp2": "Bioinorganic chemistry",

  "learnUni_chemistry_f3_name": "Analytical Chemistry",
  "learnUni_chemistry_f3_desc": "Analytical chemistry provides the tools to identify substances and measure their concentrations in complex matrices. Modern analytical techniques — HPLC, GC-MS, NMR, atomic absorption — are indispensable across pharmaceuticals, environmental monitoring, food safety, forensics, and clinical diagnostics.",
  "learnUni_chemistry_f3_kp0": "Titrimetric analysis: acid-base, complexometric (EDTA), redox, and precipitation titrations. End-point detection: indicators, pH meters, conductimetry, potentiometry. Standard solutions, primary standards, and back-titrations.",
  "learnUni_chemistry_f3_kp1": "Chromatography: stationary phase retards components differentially. GC (volatile analytes, thermal detection), HPLC (non-volatile, UV/fluorescence/MS detection), IC (ion exchange), SFC (supercritical fluid). Resolution R = 2(t₂−t₁)/(w₁+w₂).",
  "learnUni_chemistry_f3_kp2": "Mass spectrometry: electron ionisation (EI) produces radical cations that fragment characteristically. High-resolution MS gives exact molecular formula. LC-MS/MS provides selectivity for complex biological matrices.",
  "learnUni_chemistry_f3_kp3": "NMR spectroscopy: ¹H NMR: chemical shift (δ, ppm) indicates environment, coupling (J, Hz) shows adjacent H connectivity, integration gives ratio of H types. ¹³C NMR and 2D techniques (COSY, HMBC, NOESY) determine full 3D structure.",
  "learnUni_chemistry_f3_kp4": "Method validation: limit of detection (LOD), limit of quantification (LOQ), linearity (R²), accuracy (% recovery), precision (RSD%), selectivity (no interference), robustness (reproducible across labs). Required for regulatory submission (FDA, EMA).",
  "learnUni_chemistry_f3_task": "An unknown organic compound shows: MW = 122 by MS; IR: broad OH stretch 3200–3500, carbonyl 1680 cm⁻¹; ¹H NMR: δ 7.8 (d, 2H), 7.5 (d, 2H), 3.9 (s, 3H). Propose a structure. Justify each spectroscopic observation. Then describe how you would validate a HPLC method to quantify this compound in a pharmaceutical tablet.",
  "learnUni_chemistry_f3_tp0": "Titrations and chromatography",
  "learnUni_chemistry_f3_tp1": "Mass spectrometry and NMR",
  "learnUni_chemistry_f3_tp2": "Method validation",

  "learnUni_chemistry_f4_name": "Biochemistry",
  "learnUni_chemistry_f4_desc": "Biochemistry studies the chemical processes of life — enzyme catalysis, metabolic pathways, DNA replication, and cell signalling. It bridges chemistry and medicine: understanding enzyme kinetics enables drug design; understanding metabolism reveals targets for treating diabetes, cancer, and obesity; DNA biochemistry underpins CRISPR gene editing.",
  "learnUni_chemistry_f4_kp0": "Enzyme kinetics: Michaelis-Menten equation v = Vmax[S]/(Km+[S]). Km: substrate concentration at half-maximal velocity — reflects enzyme-substrate affinity. Vmax: maximum rate at saturating substrate. Linearised by Lineweaver-Burk plot (1/v vs. 1/[S]).",
  "learnUni_chemistry_f4_kp1": "Enzyme inhibition: competitive (inhibitor binds active site, increases apparent Km, Vmax unchanged); non-competitive (inhibitor binds elsewhere, decreases Vmax, Km unchanged); irreversible (covalent — aspirin acetylates COX permanently).",
  "learnUni_chemistry_f4_kp2": "Metabolism: catabolism (glucose → 2 pyruvate via glycolysis, 2 ATP; Krebs cycle 2 ATP; oxidative phosphorylation ~32 ATP via proton gradient across inner mitochondrial membrane). Total ≈36 ATP per glucose.",
  "learnUni_chemistry_f4_kp3": "DNA biochemistry: double helix stabilised by Watson-Crick base pairing (A:T, G:C) and base stacking (π-π interactions). DNA replication semi-conservative: DNA polymerase adds 5'→3', requires primer (RNA). Error rate ~1 in 10⁹ after proofreading.",
  "learnUni_chemistry_f4_kp4": "Protein structure and folding: primary (amino acid sequence) → secondary (α-helix: H-bonds i to i+4; β-sheet: parallel or anti-parallel strands) → tertiary (3D fold, hydrophobic collapse) → quaternary (multiple subunits). Chaperones assist folding; misfolding causes diseases (Alzheimer, Parkinson, prion diseases).",
  "learnUni_chemistry_f4_task": "An enzyme has Km = 2 mM and Vmax = 60 μmol/min. (a) Calculate v at [S] = 1, 2, 6 mM. (b) Draw Michaelis-Menten and Lineweaver-Burk plots for both uninhibited and competitively inhibited states (inhibitor doubles apparent Km). (c) Drug design: propose how knowledge of the enzyme's active site geometry could guide the design of a transition-state analogue inhibitor.",
  "learnUni_chemistry_f4_tp0": "Enzyme kinetics and inhibition",
  "learnUni_chemistry_f4_tp1": "Metabolism and ATP production",
  "learnUni_chemistry_f4_tp2": "DNA and protein structure",

  // ── University Biology f2-f5 ─────────────────────────────────────────

  "learnUni_biology_f2_name": "Ecology & Conservation Biology",
  "learnUni_biology_f2_desc": "University ecology applies quantitative models to population dynamics, species interactions, and ecosystem function. Conservation biology uses ecological theory — minimum viable populations, reserve design, corridor ecology — to protect biodiversity in a world undergoing rapid environmental change.",
  "learnUni_biology_f2_kp0": "Population models: logistic growth dN/dt = rN(1−N/K) where r is intrinsic rate of increase and K is carrying capacity. Maximum sustainable yield (MSY) harvested at N = K/2 where dN/dt is maximum.",
  "learnUni_biology_f2_kp1": "Lotka-Volterra predator-prey model: dN/dt = rN−aNP (prey); dP/dt = baNP−mP (predator). Populations oscillate cyclically — demonstrated by hare-lynx data. Stability analysis via eigenvalues of Jacobian.",
  "learnUni_biology_f2_kp2": "Island biogeography (MacArthur & Wilson): S_eq from balance of immigration (decreasing with S) and extinction (increasing with S) rates. Larger, closer islands have higher species richness → SLOSS debate in reserve design.",
  "learnUni_biology_f2_kp3": "Metapopulation theory (Levins): a network of local populations connected by dispersal. Fraction occupied patches p evolves: dp/dt = cp(1−p) − ep. Critical patch occupancy below which global extinction is inevitable.",
  "learnUni_biology_f2_kp4": "Conservation genomics: population genetics tools (FST, effective population size Ne, inbreeding coefficient F) identify genetically distinct populations, measure gene flow, and diagnose inbreeding depression in captive breeding programmes.",
  "learnUni_biology_f2_task": "A population of 200 wolves (K=1000, r=0.3/yr) is harvested annually. (a) Calculate the population growth rate at N=200 and at MSY. (b) What annual harvest equals the growth rate at MSY? (c) A second population on a neighbouring island has Ne=15 — what risks does this face, and what conservation actions are appropriate?",
  "learnUni_biology_f2_tp0": "Population models and MSY",
  "learnUni_biology_f2_tp1": "Predator-prey dynamics",
  "learnUni_biology_f2_tp2": "Island biogeography and conservation genomics",

  "learnUni_biology_f3_name": "Cell & Molecular Biology",
  "learnUni_biology_f3_desc": "Cell biology at university level investigates signal transduction, the cell cycle, epigenetics, and the molecular mechanisms of disease. Modern molecular biology — PCR, gene cloning, RNA-seq, CRISPR — provides tools to read, write, and edit genomes. These technologies are transforming medicine, agriculture, and basic science.",
  "learnUni_biology_f3_kp0": "Cell cycle regulation: cyclins and CDKs (cyclin-dependent kinases) drive cell cycle transitions. CDK inhibitors (p21, p27) act as brakes. Rb tumour suppressor sequesters E2F transcription factor until phosphorylated by Cyclin D-CDK4/6.",
  "learnUni_biology_f3_kp1": "Signal transduction pathways: RTK (receptor tyrosine kinase) activation → RAS/MAPK cascade → transcription factor phosphorylation → gene expression changes. PI3K/Akt/mTOR pathway: growth and survival. Both are frequently mutated in cancer.",
  "learnUni_biology_f3_kp2": "Epigenetics: heritable changes in gene expression without DNA sequence change. Histone modifications (acetylation — active; methylation — context-dependent), DNA methylation (CpG methylation silences genes), chromatin remodelling. Epigenetic reprogramming in embryogenesis and cancer.",
  "learnUni_biology_f3_kp3": "RNA biology: splicing (spliceosomes remove introns), alternative splicing (one gene → multiple proteins — ~95% of human genes are alternatively spliced), non-coding RNA (miRNA silences mRNA, lncRNA regulates chromatin), ribozymes.",
  "learnUni_biology_f3_kp4": "CRISPR-Cas9: guide RNA directs Cas9 to target sequence (next to PAM sequence). Cas9 cleaves both strands. Repair by NHEJ (error-prone → knockout) or HDR (template → precise edit). Applications: gene therapy, agriculture, basic research, diagnostics.",
  "learnUni_biology_f3_task": "A cancer cell has: (1) constitutively active RAS mutation, (2) deleted Rb gene, (3) p53 mutation. Trace the molecular consequences of each mutation through the cell cycle and signalling pathways. Identify: which checkpoint fails for each, what the consequences are for cell proliferation, and two therapeutic strategies targeting these defects.",
  "learnUni_biology_f3_tp0": "Cell cycle regulation",
  "learnUni_biology_f3_tp1": "Signal transduction and cancer",
  "learnUni_biology_f3_tp2": "Epigenetics and CRISPR",

  "learnUni_biology_f4_name": "Neuroscience",
  "learnUni_biology_f4_desc": "Neuroscience bridges molecular biology, physiology, and psychology to explain how the brain generates behaviour. From ion channels to neural circuits to consciousness, it is one of the most complex and exciting frontiers in biology. Neurological diseases affect 1 in 6 people globally — understanding them requires deep knowledge of brain structure and function.",
  "learnUni_biology_f4_kp0": "Action potential: threshold depolarisation opens voltage-gated Na⁺ channels (rapid depolarisation to +40 mV) → inactivation of Na⁺ channels + opening of K⁺ channels (repolarisation) → hyperpolarisation (refractory period). All-or-nothing, propagates without decrement along axon.",
  "learnUni_biology_f4_kp1": "Synaptic transmission: Ca²⁺ influx triggers SNARE-mediated vesicle fusion → neurotransmitter release → postsynaptic receptor binding. Ionotropic receptors (AMPA, GABA_A): fast ion flux. Metabotropic receptors (mGluR, β-adrenergic): slow G-protein cascades.",
  "learnUni_biology_f4_kp2": "Synaptic plasticity: LTP (long-term potentiation) — NMDA receptor coincidence detector (requires both glutamate binding AND postsynaptic depolarisation) → AMPA receptor insertion → increased synaptic strength. Molecular basis of learning and memory.",
  "learnUni_biology_f4_kp3": "Neural circuits: excitatory (glutamatergic) and inhibitory (GABAergic) neurons form recurrent circuits. E/I balance: disruption causes epilepsy (excess excitation) or anaesthesia (excess inhibition). Oscillations (theta, gamma) encode information and synchronise brain regions.",
  "learnUni_biology_f4_kp4": "Neurological disease mechanisms: Alzheimer's (amyloid-β plaques disrupt synaptic transmission; tau hyperphosphorylation destabilises microtubules → neuronal death), Parkinson's (dopaminergic neuron loss in substantia nigra; α-synuclein Lewy bodies), Huntington's (polyglutamine expansion in huntingtin → toxic protein aggregation, striatal neurodegeneration).",
  "learnUni_biology_f4_task": "You record from a hippocampal neuron. High-frequency stimulation of the presynaptic neuron causes LTP. Describe step-by-step the molecular events: NMDA receptor activation, Ca²⁺ signalling, CaMKII activation, AMPA receptor phosphorylation and insertion, and long-term structural changes. Then explain why blocking NMDA receptors prevents LTP formation.",
  "learnUni_biology_f4_tp0": "Action potentials and synaptic transmission",
  "learnUni_biology_f4_tp1": "Synaptic plasticity and LTP",
  "learnUni_biology_f4_tp2": "Neural circuits and neurological disease",

  "learnUni_biology_f5_name": "Immunology",
  "learnUni_biology_f5_desc": "Immunology is the study of the body's defence mechanisms. The immune system discriminates self from non-self, destroys pathogens and cancer cells, and creates immunological memory. Dysregulation causes autoimmune diseases, allergy, and immunodeficiency. Modern immunotherapies — checkpoint inhibitors, CAR-T cells, mRNA vaccines — are transforming medicine.",
  "learnUni_biology_f5_kp0": "Innate immunity: pattern recognition receptors (PRRs, e.g. Toll-like receptors) detect pathogen-associated molecular patterns (PAMPs). Activate NF-κB → inflammatory cytokines (IL-6, TNF-α, IL-1β). Complement cascade opsonises and lyses pathogens.",
  "learnUni_biology_f5_kp1": "Adaptive immunity: antigen-presenting cells (dendritic cells, macrophages) process antigens and present peptides on MHC I (to CD8⁺ cytotoxic T cells) or MHC II (to CD4⁺ helper T cells). Clonal selection and expansion of antigen-specific lymphocytes.",
  "learnUni_biology_f5_kp2": "B cell activation and antibodies: T-dependent activation requires helper T cells (CD40L-CD40 interaction + cytokines). Germinal centre reaction: somatic hypermutation + affinity maturation + class switching (IgM → IgG, IgA, IgE). Memory B cells persist for decades.",
  "learnUni_biology_f5_kp3": "Immune tolerance and autoimmunity: central tolerance — autoreactive T cells deleted in thymus (negative selection). Peripheral tolerance — regulatory T cells (Tregs) suppress autoreactive cells. Failure: systemic lupus erythematosus, rheumatoid arthritis, type 1 diabetes.",
  "learnUni_biology_f5_kp4": "Cancer immunotherapy: PD-1/PD-L1 checkpoint inhibitors block tumour immune evasion → T cell reactivation (pembrolizumab, nivolumab — Nobel Prize 2018). CAR-T cell therapy: engineer patient T cells with chimeric antigen receptor targeting tumour antigen — dramatic responses in B cell leukaemia.",
  "learnUni_biology_f5_task": "A patient presents with recurrent bacterial infections and very low immunoglobulin levels. Peripheral blood shows absent B cells but normal T cells. Diagnose the immunodeficiency (X-linked agammaglobulinaemia — BTK mutation). Explain the molecular basis: how BTK normally signals during B cell development, what goes wrong, and how intravenous immunoglobulin (IVIG) therapy works.",
  "learnUni_biology_f5_tp0": "Innate immunity and pattern recognition",
  "learnUni_biology_f5_tp1": "Adaptive immunity and B cells",
  "learnUni_biology_f5_tp2": "Tolerance, autoimmunity, and cancer immunotherapy",

  // ── University Computer Science f2-f5 ───────────────────────────────

  "learnUni_computer_science_f2_name": "Algorithms & Data Structures",
  "learnUni_computer_science_f2_desc": "Algorithms and data structures are the theoretical core of computer science. The right data structure makes an algorithm efficient; the wrong one makes it impractical. Big-O analysis, graph algorithms, and dynamic programming are the fundamental tools every software engineer must master.",
  "learnUni_computer_science_f2_kp0": "Big-O: O(1) constant, O(log n) binary search, O(n) linear scan, O(n log n) merge sort, O(n²) bubble sort, O(2ⁿ) exponential. Ω (best case), Θ (tight bound). Amortised analysis for dynamic arrays.",
  "learnUni_computer_science_f2_kp1": "Core structures: array (O(1) access), linked list (O(1) head insert), hash table (average O(1) all ops), BST (O(log n) balanced), heap (O(log n) insert/extract), trie (string prefix operations).",
  "learnUni_computer_science_f2_kp2": "Graph algorithms: BFS (shortest path unweighted, O(V+E)), DFS (cycle detection, topological sort), Dijkstra (shortest path weighted, O((V+E)log V)), Bellman-Ford (negative weights, O(VE)), Floyd-Warshall (all pairs, O(V³)).",
  "learnUni_computer_science_f2_kp3": "Dynamic programming: optimal substructure + overlapping subproblems. Memoisation (top-down) vs. tabulation (bottom-up). Classic problems: 0/1 Knapsack, LCS, Edit Distance, Matrix Chain Multiplication, Coin Change.",
  "learnUni_computer_science_f2_kp4": "NP-completeness: P (polynomial-time solvable), NP (polynomial-time verifiable). NP-complete problems (SAT, TSP, Clique) — no known polynomial algorithm. Cook-Levin theorem: SAT is NP-complete. Reductions prove NP-hardness.",
  "learnUni_computer_science_f2_task": "Implement Dijkstra's algorithm (pseudocode with priority queue) on a 6-node graph. Run it step-by-step, showing the distance table and priority queue state at each iteration. Prove time complexity O((V+E)log V). Then explain: if the graph had negative edges, why does Dijkstra fail, and how does Bellman-Ford handle them?",
  "learnUni_computer_science_f2_tp0": "Big-O and data structures",
  "learnUni_computer_science_f2_tp1": "Graph algorithms",
  "learnUni_computer_science_f2_tp2": "Dynamic programming and NP-completeness",

  "learnUni_computer_science_f3_name": "Operating Systems",
  "learnUni_computer_science_f3_desc": "Operating systems are the software layer between hardware and applications — managing processes, memory, storage, and security. Understanding OS internals enables you to write efficient, concurrent code, understand system performance, and design secure distributed systems.",
  "learnUni_computer_science_f3_kp0": "Process vs. thread: a process has its own address space and resources; threads share the process address space. Context switching: OS saves/restores CPU state (registers, PC, stack pointer). Scheduling: FCFS, SJF, Round Robin, Priority, Multilevel Queue.",
  "learnUni_computer_science_f3_kp1": "Concurrency hazards: race conditions, deadlock (Coffman conditions: mutual exclusion, hold-and-wait, no preemption, circular wait), starvation, livelock. Synchronisation: mutex, semaphore, monitor (condition variables), read-write locks.",
  "learnUni_computer_science_f3_kp2": "Memory management: paging — divide virtual address space into fixed-size pages mapped to physical frames via page table. TLB caches recent translations. Page replacement algorithms: FIFO, LRU, Clock (second chance). Thrashing when working set > RAM.",
  "learnUni_computer_science_f3_kp3": "File systems: VFS (Virtual File System) layer for portability. Inodes: file metadata + data block pointers. Journaling (ext4, NTFS) for crash consistency. B-trees used in HFS+, NTFS for directory indexing. RAID levels 0,1,5,6 — performance and redundancy trade-offs.",
  "learnUni_computer_science_f3_kp4": "Security architecture: ring protection (user mode vs. kernel mode, syscalls as controlled boundary), capability-based access control, mandatory access control (SELinux/AppArmor), hypervisors (type 1 bare metal: VMware ESXi, Xen; type 2 hosted: VirtualBox). Containers (Docker) use cgroups and namespaces — not true VMs.",
  "learnUni_computer_science_f3_task": "Three processes share resources R1 and R2. P1: holds R1, needs R2. P2: holds R2, needs R1. P3: needs both. (a) Draw the resource allocation graph and detect the deadlock. (b) Show a safe state using the Banker's Algorithm: Max=[R1:2,R2:1], [R1:1,R2:2], [R1:2,R2:2]; Available=[R1:1,R2:1]. Find a safe execution sequence. (c) Propose a protocol to prevent this deadlock.",
  "learnUni_computer_science_f3_tp0": "Process scheduling and concurrency",
  "learnUni_computer_science_f3_tp1": "Memory management and virtual memory",
  "learnUni_computer_science_f3_tp2": "File systems and OS security",

  "learnUni_computer_science_f4_name": "Software Engineering",
  "learnUni_computer_science_f4_desc": "Software engineering applies systematic methods to building reliable, maintainable, scalable software. Modern practices — Agile, DevOps, microservices, CI/CD — have transformed how software is delivered. Core engineering disciplines — requirements, architecture, testing, and security — remain essential regardless of methodology.",
  "learnUni_computer_science_f4_kp0": "Agile (Scrum, XP, Kanban): iterative 2-week sprints, daily standups, sprint retrospectives, backlog grooming. DevOps: development and operations integrated; CI/CD pipelines (GitLab CI, Jenkins, GitHub Actions) automate build, test, deploy on every commit.",
  "learnUni_computer_science_f4_kp1": "Software architecture patterns: layered (UI → business logic → data access), microservices (independently deployable services with own databases, communicate via REST/gRPC/messaging), event-driven (services react to events — Kafka, RabbitMQ), CQRS+Event Sourcing.",
  "learnUni_computer_science_f4_kp2": "Design patterns (GoF): Creational (Singleton, Factory, Builder, Prototype), Structural (Adapter, Decorator, Facade, Proxy), Behavioural (Observer, Strategy, Command, Template Method, Iterator). Know when to apply — don't over-engineer.",
  "learnUni_computer_science_f4_kp3": "Testing strategy: unit (fast, isolated — mock dependencies), integration (multiple components), contract (API compatibility), system (end-to-end), acceptance (user story validation). TDD: red-green-refactor. Mutation testing verifies test quality.",
  "learnUni_computer_science_f4_kp4": "Security in software engineering (OWASP Top 10): injection (SQL, command), broken authentication, XSS, insecure direct object references, security misconfiguration. Threat modelling (STRIDE), secure code review, dependency vulnerability scanning (Snyk, Dependabot).",
  "learnUni_computer_science_f4_task": "Design a ride-sharing application: (a) Write 5 user stories with acceptance criteria. (b) Draw a C4 architecture diagram (context, container, component levels). (c) Identify 3 design patterns used and justify. (d) Write unit tests (pseudocode) for the 'calculate fare' function covering: base fare, surge pricing, minimum fare, and edge cases (zero distance, negative inputs). (e) Identify 3 OWASP security risks and mitigations.",
  "learnUni_computer_science_f4_tp0": "Agile, DevOps, and CI/CD",
  "learnUni_computer_science_f4_tp1": "Architecture and design patterns",
  "learnUni_computer_science_f4_tp2": "Testing and security engineering",

  "learnUni_computer_science_f5_name": "Machine Learning & AI",
  "learnUni_computer_science_f5_desc": "Machine learning (ML) enables systems to learn from data. Deep learning — neural networks with many layers — has driven breakthroughs in vision, language, and games. Understanding ML theory (bias-variance, VC dimension, regularisation) and practice (PyTorch, hyperparameter tuning, deployment) is now a core competency in computer science.",
  "learnUni_computer_science_f5_kp0": "Supervised learning: minimise loss L(θ) over training data via gradient descent θ ← θ − α∇L. Stochastic gradient descent (SGD), Adam optimiser. Regularisation: L2 (weight decay, shrinks weights), L1 (sparsity), dropout (randomly zeroes neurons during training).",
  "learnUni_computer_science_f5_kp1": "Neural network architecture: fully connected (dense), convolutional (CNN — weight sharing, translation invariance — ideal for images), recurrent (RNN, LSTM, GRU — sequential data), attention mechanism (Transformer — self-attention, O(n²) complexity, but parallelisable).",
  "learnUni_computer_science_f5_kp2": "Bias-variance trade-off: training error ≈ bias²; test error − training error ≈ variance. Under-fitting: high bias (model too simple). Over-fitting: high variance (model memorises training data). Regularisation, more data, and simpler models address over-fitting.",
  "learnUni_computer_science_f5_kp3": "Evaluation beyond accuracy: for imbalanced classes — precision (TP/TP+FP), recall (TP/TP+FN), F1 = 2PR/(P+R), AUC-ROC (area under receiver operating characteristic curve). k-fold cross-validation gives robust generalisation estimate.",
  "learnUni_computer_science_f5_kp4": "Foundation models and responsible AI: large language models (GPT, BERT) pre-trained on vast data, fine-tuned for specific tasks. Hallucinations, bias, and misuse are serious risks. EU AI Act (2024) classifies AI systems by risk and imposes requirements for high-risk applications.",
  "learnUni_computer_science_f5_task": "You build a sentiment classifier (positive/negative reviews). Training accuracy: 97%; validation accuracy: 68%. (a) Diagnose the problem. (b) List 4 techniques to fix it. (c) Your dataset is 90% positive — calculate accuracy, precision, recall, and F1 if you classify everything as positive. Why is F1 a better metric? (d) Draw precision-recall curves for two models and explain which you would choose for a medical diagnosis task.",
  "learnUni_computer_science_f5_tp0": "Neural network training and optimisation",
  "learnUni_computer_science_f5_tp1": "Bias-variance and regularisation",
  "learnUni_computer_science_f5_tp2": "Evaluation metrics and responsible AI",

  // ── University Economics f1-f4 ───────────────────────────────────────

  "learnUni_economics_f1_name": "Microeconomics",
  "learnUni_economics_f1_desc": "Microeconomics analyses decision-making by households, firms, and markets. Consumer and firm theory, market structures from perfect competition to monopoly, externalities, and game theory provide the core analytical toolkit for understanding prices, market outcomes, and the welfare effects of policy.",
  "learnUni_economics_f1_kp0": "Consumer theory: utility maximisation subject to budget constraint. At optimum: MU_x/P_x = MU_y/P_y (equal marginal utility per pound). Indifference curves + budget line → tangency condition MRS = price ratio.",
  "learnUni_economics_f1_kp1": "Firm theory: profit maximisation where MR = MC. Perfect competition: P = MR = MC in long-run equilibrium, zero economic profit. Short run: shutdown if P < min(AVC).",
  "learnUni_economics_f1_kp2": "Market structures: monopoly (MR < P, deadweight loss = welfare loss, natural monopoly regulated by price cap or cost-plus); oligopoly (Cournot — quantity competition, Bertrand — price competition → marginal cost pricing).",
  "learnUni_economics_f1_kp3": "Externalities and public goods: negative externality → overproduction (Pigouvian tax = MEC corrects). Positive externality → underproduction (subsidy corrects). Public goods: non-excludable + non-rival → free rider problem → undersupply by market.",
  "learnUni_economics_f1_kp4": "Game theory: Nash equilibrium (no unilateral profitable deviation). Prisoner's dilemma: dominant strategy leads to Pareto-inferior outcome. Repeated games: cooperation sustainable via trigger strategies if discount factor high enough. Auction theory: first-price (bid below value), second-price/Vickrey (dominant strategy to bid true value).",
  "learnUni_economics_f1_task": "Two airlines compete on a route. Each can set High or Low price. Payoff matrix (profit £m): {H,H}=(10,10), {H,L}=(2,15), {L,H}=(15,2), {L,L}=(5,5). (a) Find Nash equilibrium. (b) Is it Pareto optimal? (c) If the game is repeated indefinitely, when can cooperation be sustained (derive condition on discount factor δ)? (d) How does competition law view airline price coordination?",
  "learnUni_economics_f1_tp0": "Consumer and firm theory",
  "learnUni_economics_f1_tp1": "Market structures and monopoly",
  "learnUni_economics_f1_tp2": "Externalities and game theory",

  "learnUni_economics_f2_name": "Econometrics",
  "learnUni_economics_f2_desc": "Econometrics provides the statistical tools to test economic theories and estimate causal relationships from observational data. OLS regression, instrumental variables, and panel data methods are the workhorses. The modern 'credibility revolution' emphasises rigorous identification of causal effects using natural experiments.",
  "learnUni_economics_f2_kp0": "OLS: minimise Σεᵢ² to estimate β̂ = (X'X)⁻¹X'y. Gauss-Markov: OLS is BLUE under no endogeneity, homoskedasticity, no perfect multicollinearity. Unbiasedness: E[β̂] = β. Consistency: β̂ →_p β as n → ∞.",
  "learnUni_economics_f2_kp1": "Endogeneity: E[ε|X] ≠ 0 due to omitted variable bias, reverse causality, or measurement error → OLS biased and inconsistent. IV solution: find instrument Z correlated with X (relevance: Cov(Z,X) ≠ 0) but not with ε (exclusion: Cov(Z,ε) = 0).",
  "learnUni_economics_f2_kp2": "Panel data: Yᵢₜ = α + βXᵢₜ + μᵢ + εᵢₜ. Fixed effects (within estimator): eliminates time-invariant unobserved heterogeneity μᵢ. Random effects: more efficient if μᵢ uncorrelated with X (test: Hausman). First difference: Δyᵢₜ = βΔxᵢₜ + Δεᵢₜ.",
  "learnUni_economics_f2_kp3": "Difference-in-differences (DiD): compare treatment and control groups before/after a policy change. β_DiD = (Ȳ_{treatment,post} − Ȳ_{treatment,pre}) − (Ȳ_{control,post} − Ȳ_{control,pre}). Key assumption: parallel trends (absent treatment, both groups would have evolved identically).",
  "learnUni_economics_f2_kp4": "Regression discontinuity (RD): treatment is assigned based on whether a running variable crosses a threshold. Compares outcomes just above and below the cutoff — local randomisation. Sharp RD: all cross the threshold. Fuzzy RD: only some — use as instrument.",
  "learnUni_economics_f2_task": "You want to estimate the causal effect of university education on earnings. OLS gives β̂ = 0.08 (8% wage premium per year of education). (a) Why is OLS likely biased? (b) Propose an instrument — state why it satisfies relevance and exclusion restrictions. (c) Describe a DiD strategy using a natural experiment (e.g. a tuition fee change) with parallel trends assumption. (d) Interpret a regression discontinuity design around a scholarship eligibility threshold.",
  "learnUni_economics_f2_tp0": "OLS and assumptions",
  "learnUni_economics_f2_tp1": "Instrumental variables",
  "learnUni_economics_f2_tp2": "DiD and regression discontinuity",

  "learnUni_economics_f3_name": "Behavioural Economics",
  "learnUni_economics_f3_desc": "Behavioural economics incorporates psychological insights into economic analysis. People are not perfectly rational — they are loss-averse, present-biased, influenced by framing and social norms. These deviations are predictable and systematic, enabling better policy design through nudges and choice architecture.",
  "learnUni_economics_f3_kp0": "Prospect theory (Kahneman & Tversky, 1979): people evaluate outcomes relative to a reference point. Value function: concave for gains (risk aversion), convex for losses (risk seeking), steeper for losses than gains (λ ≈ 2 — loss aversion coefficient).",
  "learnUni_economics_f3_kp1": "Probability weighting: people overweight small probabilities (explains lotteries and insurance) and underweight large probabilities. Cumulative prospect theory handles compound lotteries.",
  "learnUni_economics_f3_kp2": "Present bias: quasi-hyperbolic discounting U = u₀ + βΣδᵗuₜ with β < 1. Generates time inconsistency — plans made now won't be followed. Explains over-eating, under-saving, procrastination. Sophisticates know they're biased; naives don't — different policy implications.",
  "learnUni_economics_f3_kp3": "Nudge theory (Thaler & Sunstein, 2008): choice architecture shapes decisions without restricting freedom. Default rules (pension auto-enrolment), social norm messages ('most households pay on time'), and simplification reduce barriers to desirable behaviour.",
  "learnUni_economics_f3_kp4": "Experimental economics and RCTs: lab experiments test theory in controlled settings. Field experiments (RCTs) test interventions at scale. Randomistas (Banerjee, Duflo — Nobel 2019) revolutionised development economics by rigorously testing specific interventions.",
  "learnUni_economics_f3_task": "Model a present-biased individual (β=0.7, δ=0.95) deciding whether to exercise today (cost c=5 utils) for future benefit (B=10 utils received next week). (a) Does the individual plan on Sunday to exercise on Monday? (b) When Monday arrives, do they actually exercise? (c) Explain time inconsistency. (d) Design a commitment device to help them, and compare it to a financial penalty nudge.",
  "learnUni_economics_f3_tp0": "Prospect theory and loss aversion",
  "learnUni_economics_f3_tp1": "Present bias and time inconsistency",
  "learnUni_economics_f3_tp2": "Nudge theory and experimental economics",

  "learnUni_economics_f4_name": "Development Economics",
  "learnUni_economics_f4_desc": "Development economics studies the causes of poverty and the policies that promote prosperity. Modern development economics has moved from grand theories toward rigorous empirical evidence on specific interventions — using RCTs, natural experiments, and big data. The field engages with growth, institutions, health, education, and inequality.",
  "learnUni_economics_f4_kp0": "Solow growth model: Y = AK^α L^{1−α}. Steady state: investment = depreciation; savings rate and population growth determine K/L ratio. Diminishing returns → conditional convergence. Residual A (total factor productivity) drives long-run growth — but is exogenous in Solow.",
  "learnUni_economics_f4_kp1": "Endogenous growth (Romer 1990): knowledge K̃ enters production without diminishing returns. R&D sector produces new ideas. Knowledge spillovers (non-rival, partially excludable) → undersupply of innovation without IP protection or R&D subsidies.",
  "learnUni_economics_f4_kp2": "Institutions and growth (Acemoglu & Robinson): inclusive institutions (property rights, rule of law, competitive markets) foster growth. Extractive institutions (colonial legacy — settler mortality shaped colonial institutions) trap countries in poverty. History matters — persistence.",
  "learnUni_economics_f4_kp3": "RCTs in development: Duflo & Banerjee (Abdul Latif Jameel Poverty Action Lab, J-PAL) use RCTs to evaluate specific interventions — deworming, microcredit, conditional cash transfers, fertiliser nudges. Results often surprising — theory without data misleads.",
  "learnUni_economics_f4_kp4": "Poverty traps and CCTs: poverty traps arise from fixed costs of investment (education, health, fertiliser) that low-income households cannot afford, preventing productivity gains. Conditional cash transfers (Mexico's Oportunidades, Brazil's Bolsa Família) provide income conditioned on school attendance and healthcare — breaking the trap with measured long-run effects.",
  "learnUni_economics_f4_task": "Compare South Korea and Nigeria: both had similar income levels (~$300 GDP/capita) in 1960. In 2023 South Korea has ~$33,000, Nigeria ~$2,100. Using (a) Solow model — what savings and human capital differences explain divergence? (b) Romer model — how does innovation capacity matter? (c) Acemoglu & Robinson — compare colonial history and institutional trajectories. Conclude with one evidence-based policy recommendation for Nigeria, citing a relevant RCT.",
  "learnUni_economics_f4_tp0": "Solow and endogenous growth models",
  "learnUni_economics_f4_tp1": "Institutions and development",
  "learnUni_economics_f4_tp2": "RCTs, CCTs, and poverty traps"

};

let added = 0;
for (const [k, v] of Object.entries(keys)) {
  if (!en[k]) { en[k] = v; added++; }
}
fs.writeFileSync(enPath, JSON.stringify(en, null, 2), 'utf8');
console.log('Batch D done. Added', added, 'new keys. Total:', Object.keys(en).length);
